#include<bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<ll, ll>PII
using namespace std;
CI MAXN=1e1+5;
int n;
char t[MAXN][MAXN],ans[MAXN][MAXN],p[MAXN][MAXN];
void a()
{
	char tmp[MAXN][MAXN];
	for(int i=1;i<=n;++i)
	{
		for(int j=1;j<=n;++j)
		{
			tmp[i][j]=t[i][j];
		}
	}
	for(int i=1,xi=n;i<=n;++i,--xi)
	{
		for(int j=1;j<=n;++j)
		{
			t[j][xi]=tmp[i][j];
		}
	}
}//正常转90 
void b()
{
	char tmp[MAXN][MAXN];
	for(int i=1;i<=n;++i)
	{
		for(int j=1;j<=n;++j)
		{
			tmp[i][j]=p[i][j];
		}
	}
	for(int i=1,xi=n;i<=n;++i,--xi)
	{
		for(int j=1;j<=n;++j)
		{
			p[j][xi]=tmp[i][j];
		}
	}
}//水平反转转90 
int main(void){
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
	cin>>n;
	for(int i=1;i<=n;++i)
	{
		for(int j=1;j<=n;++j)
		{
			cin>>t[i][j];
		}
	}
	for(int i=1;i<=n;++i)
	{
		for(int j=1,xi=n;j<=n;++j,--xi)
		{
			cin>>ans[i][j];
			p[i][xi]=t[i][j];
		}
	}
	for(int i=1;i<=3;++i)
	{
		a();
		bool flag=true;
		for(int j=1;j<=n;++j)
		{
			for(int k=1;k<=n;++k)
			{
				if(t[j][k]!=ans[j][k])flag=false;
			}
		}
		if(flag)
		{
			printf("%d",i);
			exit(0);
		}
	}
	for(int i=1;i<=4;++i)
	{
		bool flag=true;
		for(int j=1;j<=n;++j)
		{
			for(int k=1;k<=n;++k)
			{
				if(p[j][k]!=ans[j][k])flag=false;
			}
		}
		if(flag)
		{
			if(i==1)printf("4");
			else printf("5");
			exit(0);
		}
		b();
	}
	bool flag=true;
	for(int j=1;j<=n;++j)
	{
		for(int k=1;k<=n;++k)
		{
			if(t[j][k]!=ans[j][k])flag=false;
		}
	}
	if(flag)printf("6"); 
	else printf("7"); 
	
	
	return false;
}
